export const code = async (inputs) => {
  const event       = inputs.event      || {};
  const patients    = Array.isArray(inputs.patients)   ? inputs.patients   : [];
  const optOutList  = Array.isArray(inputs.optOutList) ? inputs.optOutList : [];
  const githubToken = inputs.githubToken || '';

  const queueId    = event['A'] || '';
  const waMsgId    = event['B'] || '';
  const fromPhone  = (event['C'] || '').toString().trim();
  const eventType  = (event['D'] || '').toString().toLowerCase().trim();
  const rawPayload = event['E'] || '{}';

  if (eventType !== 'incoming_message' && eventType !== 'message') {
    return {
      action: 'status_update', eventType, queueId, fromPhone, waMsgId,
      sentiment: 'unknown', patientStatus: 'status_update', messageText: '',
      patientRow: '', corrId: '', clinicId: '', patientName: 'Unknown', aiUsed: false, debugError: ''
    };
  }

  let messageText = '';
  try {
    if (rawPayload.startsWith('{')) {
      const parsed = JSON.parse(rawPayload);
      messageText = parsed?.entry?.[0]?.changes?.[0]?.value?.messages?.[0]?.text?.body || '';
    } else {
      messageText = rawPayload;
    }
  } catch(e) {
    messageText = rawPayload || '';
  }

  const normalize = (p) => {
    let s = p.toString().replace(/[^0-9]/g, '');
    if (s.startsWith('0091')) s = s.slice(2);
    if (s.length === 10) s = '91' + s;
    return s;
  };
  const fromPhoneNorm = normalize(fromPhone);
  const lower = messageText.toLowerCase();

  const wrongKws = ['wrong number','galat number','yeh kaun','kaun hai','who is this'];
  if (wrongKws.some(k => lower.includes(k))) {
    return {
      action: 'WRONG_NUMBER', patientStatus: 'wrong_number', sentiment: 'wrong_number',
      messageText, fromPhone, fromPhoneNorm, patientName: 'Unknown',
      clinicId: '', corrId: '', patientRow: '', queueId, waMsgId, patientId: '', aiUsed: false, debugError: ''
    };
  }

  const patient = patients.find(p => {
    const pv = p['values'] || p;
    return normalize((pv['F'] || '').toString()) === fromPhoneNorm;
  });

  if (!patient) {
    return {
      action: 'unmatched', fromPhone, fromPhoneNorm, messageText, queueId, waMsgId,
      sentiment: 'unknown', patientStatus: 'unmatched', patientRow: '', corrId: '',
      clinicId: '', patientName: 'Unknown', aiUsed: false, debugError: ''
    };
  }

  const pv          = patient['values'] || patient;
  const patientRow  = patient['row']  || '';
  const corrId      = pv['B'] || '';
  const clinicId    = pv['C'] || '';
  const patientName = pv['D'] || 'Patient';
  const patientId   = pv['A'] || '';

  const optOutKws = ['stop','band karo','mat bhejo','remove','unsubscribe','hatao','रोको','बंद करो'];
  if (optOutKws.some(k => lower.includes(k))) {
    return {
      action: 'opt_out', sentiment: 'opt_out', patientStatus: 'opted_out',
      messageText, fromPhone, fromPhoneNorm, patientName, clinicId, corrId,
      patientRow, queueId, waMsgId, patientId, aiUsed: false, debugError: ''
    };
  }

  // MICROSOFT AI — GitHub Models GPT-5
  let aiSentiment = null;
  let aiUsed = false;
  let debugError = '';

  if (githubToken && messageText) {
    try {
      const aiResp = await fetch('https://models.github.ai/inference/chat/completions', 
  {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${githubToken}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          model: 'deepseek/DeepSeek-V3-0324',
          messages: [
            {
              role: 'system',
              content: `You are an AI assistant for an Indian medical clinic's patient follow-up system. Analyze the patient's WhatsApp message and classify their sentiment. Reply with ONLY one word: POSITIVE, NEGATIVE, NEUTRAL, or OPT_OUT.`
            },
            {
              role: 'user',
              content: messageText
            }
          ],
          max_tokens: 5,
          temperature: 0
        })
      });

      if (aiResp.ok) {
        const aiData = await aiResp.json();
        const rawAI = (aiData?.choices?.[0]?.message?.content || '').trim().toUpperCase();
        if (['POSITIVE','NEGATIVE','NEUTRAL','OPT_OUT'].includes(rawAI)) {
          aiSentiment = rawAI;
          aiUsed = true;
        } else {
          debugError = 'Bad AI response: ' + rawAI;
        }
      } else {
        const errText = await aiResp.text();
        debugError = `HTTP ${aiResp.status}: ${errText}`;
      }
    } catch(e) {
      debugError = 'FETCH ERROR: ' + e.message;
    }
  } else {
    debugError = githubToken ? 'No messageText' : 'No githubToken in inputs';
  }

  // Smart keyword fallback
  let finalSentiment = aiSentiment;
  if (!finalSentiment) {
    const posPhrases = [
      'dard kam','dard nahi','dard thoda kam','dard khatam',
      'ठीक','अच्छा','बेहतर','सुधार','बढ़िया',
      'better','good','great','fine','okay','ok','well','perfect',
      'theek','shukriya','thank','thanks','recovered','comfortable',
      'no pain','feeling good','👍','😊','✅','kam ho gaya','aram hai','relief'
    ];
    const negPhrases = [
      'aur dard hai','bahut dard','dard badh','dard zyada','zyada dard',
      'bahut takleef','bohot takleef','तकलीफ','दिक्कत','खराब','सूजन','बुखार','समस्या',
      'hurt','worse','fever','bleeding','swelling','emergency',
      'not okay','not good','getting worse','nahi theek','theek nahi'
    ];

    const isPos = posPhrases.some(k => lower.includes(k) || messageText.includes(k));
    const isNeg = !isPos && negPhrases.some(k => lower.includes(k) || messageText.includes(k));

    if (isNeg) finalSentiment = 'NEGATIVE';
    else if (isPos) finalSentiment = 'POSITIVE';
    else finalSentiment = 'NEUTRAL';
  }

  const sentimentMap = {
    'POSITIVE': { sentiment: 'positive', patientStatus: 'replied_positive' },
    'NEGATIVE': { sentiment: 'negative', patientStatus: 'replied_negative' },
    'NEUTRAL':  { sentiment: 'neutral',  patientStatus: 'replied_neutral'  },
    'OPT_OUT':  { sentiment: 'opt_out',  patientStatus: 'opted_out'        }
  };
  const result = sentimentMap[finalSentiment] || sentimentMap['NEUTRAL'];

  return {
    action: finalSentiment === 'OPT_OUT' ? 'opt_out' : 'route',
    sentiment: result.sentiment,
    patientStatus: result.patientStatus,
    messageText, fromPhone, fromPhoneNorm, patientName,
    clinicId, corrId, patientRow, queueId, waMsgId, patientId,
    aiUsed,
    debugError
  };
};
